INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('immigration-1aab856d-moex-00150', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '國際反恐法律框架是由聯合國安全理事會《1373號決議案》及相關公約與議定書所構成，而根據 《1373號決議案》的規定，完整的法律框架應包括四項主要內容，分別是將恐怖主義定罪等，下 列何者並非此規定的主要內容？', '["採取必要措施使定罪有效", "進行刑事事項方面的國際合作", "批准與執行國際反恐文書", "異議人士及政治犯的申請與庇護"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00151', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '國境管理部門在推動人流管理工作時，要在現場部署執法和任務支持人員與設備的適當級別及優 先等級以有效防制非正常移民，則下列何選項並不是主要的改進執法效率的方法？', '["戰術機動性和行動自由", "層級途徑和反制非法跨境網絡", "推動移徙者人道服務倡議", "落實數位邊境巡邏"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00152', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '90 年代初，國際上對於人口販運受害者之訪談經由執法部門和心理學家合作，開發了一種標準 調查性訪談技術—「和平模型」（PEACEmodel）的步驟程序，包括：規劃和準備（Planningand preparation,P）、參與和解釋（Engageandexplain,E）、結束（Closure,C）、評估（Evaluation, E）以及下列何項步驟？', '["敍述（Account,A）", "分析（Analysis,A）", "進入（Access,A）", "緩和情緒（Anodyne,A）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00153', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '有關疑似人口販運被害人之安置庇護，經鑑別為被害人，若是持工作簽證入境而遭剝削者，是由 轄區的何種單位提供安置保護？', '["勞政單位", "內政部移民署", "社福單位", "醫療單位"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00154', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '從政治學的理論角度探討移民問題，一般聚焦於三項主題，分別是：民族國家對移徙流動的控制， 因此也及於邊境之各項管理思考；移徙對於主權與公民權的衝擊，亦即一方面對於移徙關係之間 及另方面之外交政策與國家安全之間的衝擊；以及下列那項主題？', '["併入的問題", "勞工市場的問題", "人力資本的問題", "沒有受害者的犯罪問題"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00155', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '「聯合國開發計畫署」（UnitedNationsDevelopmentProgramme,UNDP）之《克服障礙：人員流 動與發展》（OvercomingBarriers：HumanMobilityandDevelopment）報告指出，在放寬與簡化 正常的移徙管道方面，有三項重要工作包括：正常化有關季節性或循環性之移徙、放寬對低技術 勞工的入境條件，以及下列那項工作？', '["有效處理非正常移民", "掌握復甦機會，以因應反移民主義且填補發展所需", "更新以往對移徙之既有認知，俾有利移民之正常發展", "利得與風險之平衡思考，並以具體政策尋求廣泛支持"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00156', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '依據聯合國大會決議通過《安全、有序及正常移徙之全球契約》（GlobalCompactforSafe,Orderly andRegularMigration）的要求，在收集和利用準確分類資料作為基於證據政策的依據方面，要求 及時提供移民各個階段的準確資訊，下列何項不屬於此等要求的作為？', '["推廣一個集中和公開的國家網站，提供正常移民管道資訊", "通過聯合資料庫、線上平臺等交流移民趨勢的資訊", "避免在移民路線沿線建立開放和方便使用的資訊站", "向新來移民提供說明移民的全面權利和義務相關資訊"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00157', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '所謂難民的「終止條款」（cessationclauses），《1951年關於難民地位的公約》第1C(1)至(6)條 詳細說明了難民不再是難民的條件。其中，下列何項不是反映了難民自身造成的情況變化？', '["自願重新獲得國家保護", "自願重新獲得國籍", "取得新國籍", "作為無國籍人，因被承認為難民的情況已不復存在，能夠返回原慣常居住國"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00158', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '「國家人權行動計畫」中有關外籍移工平等與不歧視部分，為確保外籍移工享有尊嚴勞動與生活 條件提出多項行動計畫，下列何者未包含在內？', '["提升移工食物、飲水", "政府直聘外國移工", "提升移工生活照顧服務", "提升移工職業衛生安全"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL),
  ('immigration-1aab856d-moex-00159', 'immigration-1aab856d', 'immigration-1aab856d-moex-113-0e6322b2', 'sub-immigration-1aab856d-01', NULL, 'single_choice', '「國家人權行動計畫」中有關難民權利保障之行動計畫，下列何者不在其中？', '["制定難民法", "建立難民移民評分政策，以吸引專技難民居留我國", "完備中國大陸人士政治考量專案長期居留制度：修正臺灣地區與大陸地區人民關係條例", "執行香港人道援助關懷行動專案"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:27:53+00:00", "source_pdf_sha1": "a9d20ecd656f", "answer_pdf_sha1": "d8a497112a3e", "source_family": "moex-gov-tw", "moex": {"exam_code": "113060", "c": "801", "s": "0711", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國土安全與移民政策(包括移民人權)", "year": "113", "exam_name": "113年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "immigration", "civil_category": "移民行政"}'::jsonb, NULL)
